class LoginPage{constructor(){this.users=[],this.init()}init(){localStorage.getItem("user_id")?window.location.href="/":this.loadUsers()}async loadUsers(){const e=document.getElementById("loading"),s=document.getElementById("error-message"),t=document.getElementById("users-container");try{e.classList.remove("hidden"),s.classList.add("hidden"),t.classList.add("hidden");const n=await window.app.apiRequest("/users");this.users=n,e.classList.add("hidden"),t.classList.remove("hidden"),this.renderUsers()}catch(t){e.classList.add("hidden"),s.classList.remove("hidden")}}renderUsers(){document.getElementById("users-container").innerHTML=this.users.map((e,s)=>`\n            <div class="user-card" onclick="loginPage.selectUser(${e.id}, '${e.name}', '${e.role}')" style="animation-delay: ${.1*s}s">\n                <div class="user-name">${e.name}</div>\n                <div class="user-role">${"admin"===e.role?"Администратор":"Сотрудник"}</div>\n            </div>\n        `).join("")}selectUser(e,s,t){localStorage.setItem("user_id",e),localStorage.setItem("user_name",s),localStorage.setItem("user_role",t),window.app.showMessage(`Вы вошли как ${s}`,"success","Вход выполнен"),setTimeout(()=>{window.location.href="/"},1e3)}}document.addEventListener("DOMContentLoaded",()=>{window.loginPage=new LoginPage});